import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import org.openqa.selenium.TimeoutException;
import java.time.Duration;

public class WaitUtils {

    public static WebElement waitForVisible(WebDriver driver, String cssSelector) {
        try {
            return new WebDriverWait(driver, Duration.ofSeconds(10))
                    .until(ExpectedConditions.visibilityOfElementLocated(
                            By.cssSelector(cssSelector)));
        } catch (TimeoutException e) {
            throw new RuntimeException(
                    "Element not visible within 10 seconds: " + cssSelector, e);
        }
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

public class IframeUtils {

    public static void clickInsideIframe(WebDriver driver, String iframeId, String buttonCssSelector) {
        WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(5));

        wait.until(ExpectedConditions.frameToBeAvailableAndSwitchToIt(
                By.id(iframeId)));
        try {
            driver.findElement(By.cssSelector(buttonCssSelector)).click();
        } finally {
            driver.switchTo().defaultContent();
        }
    }
}

import org.openqa.selenium.Alert;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

public class AlertUtils {

    public static String handleAlert(WebDriver driver, boolean accept) {
        Alert alert = new WebDriverWait(driver, Duration.ofSeconds(5))
                .until(ExpectedConditions.alertIsPresent());
        String text = alert.getText();
        if (accept) {
            alert.accept();
        } else {
            alert.dismiss();
        }
        return text;
    }
}

import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;
import java.util.Set;

public class WindowUtils {

    public static String getTitleOfNewTab(WebDriver driver, WebElement linkElement) {
        Set<String> existingHandles = driver.getWindowHandles();
        linkElement.click();

        new WebDriverWait(driver, Duration.ofSeconds(10))
                .until(ExpectedConditions.numberOfWindowsToBe(existingHandles.size() + 1));

        String newHandle = driver.getWindowHandles().stream()
                .filter(h -> !existingHandles.contains(h))
                .findFirst()
                .orElseThrow(() -> new RuntimeException("New window handle not found"));

        driver.switchTo().window(newHandle);
        return driver.getTitle();
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.StaleElementReferenceException;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.FluentWait;
import java.time.Duration;

public class FluentWaitUtils {

    public static WebElement fluentFind(WebDriver driver, By locator) {
        FluentWait<WebDriver> wait = new FluentWait<>(driver)
                .withTimeout(Duration.ofSeconds(20))
                .pollingEvery(Duration.ofSeconds(2))
                .ignoring(NoSuchElementException.class)
                .ignoring(StaleElementReferenceException.class);

        return wait.until(d -> {
            WebElement el = d.findElement(locator);
            return el.isDisplayed() ? el : null;
        });
    }
}

