import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.FindBy;
import org.openqa.selenium.support.PageFactory;

public class LoginPage {

    private final WebDriver driver;

    @FindBy(id = "username")
    private WebElement usernameField;

    @FindBy(id = "password")
    private WebElement passwordField;

    @FindBy(id = "login-btn")
    private WebElement loginButton;

    @FindBy(id = "error-msg")
    private WebElement errorMessage;

    public LoginPage(WebDriver driver) {
        this.driver = driver;
        PageFactory.initElements(driver, this);
    }

    public void login(String username, String password) {
        usernameField.clear();
        usernameField.sendKeys(username);
        passwordField.clear();
        passwordField.sendKeys(password);
        loginButton.click();
    }

    public String getErrorMessage() {
        try {
            return errorMessage.isDisplayed() ? errorMessage.getText() : "";
        } catch (NoSuchElementException e) {
            return "";
        }
    }
}

import org.openqa.selenium.StaleElementReferenceException;
import org.openqa.selenium.WebElement;
import java.util.function.Consumer;
import java.util.function.Supplier;

public class RetryUtils {

    public static void retryOnStale(
            Supplier<WebElement> locator,
            Consumer<WebElement> action,
            int maxRetries) {

        StaleElementReferenceException lastException = null;

        for (int attempt = 0; attempt < maxRetries; attempt++) {
            try {
                WebElement element = locator.get();
                action.accept(element);
                return;
            } catch (StaleElementReferenceException e) {
                lastException = e;
            }
        }
        throw lastException;
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import java.util.Arrays;

public class LocatorUtils {

    public static WebElement findByAny(WebDriver driver, By... locators) {
        for (By locator : locators) {
            try {
                return driver.findElement(locator);
            } catch (NoSuchElementException ignored) {
                // try next locator
            }
        }
        throw new NoSuchElementException(
                "Element not found with any of: " + Arrays.toString(locators));
    }
}
